    int b = 0;
    int c = 0;
    int d = 0;
    std::cin >> a >> b >> c >> d;

    int total{ 0 };
    total = total + a;
    total = total + b;
    total = total + c;
    total = total + d;

    std::cout << total << '\n';

    return 0;
}

